  const svelteSource: string = "// In your Svelte component:\nimport SignaturePad from \"lily-design-system-svelte-headless/components/SignaturePad/SignaturePad.svelte\";\n\n<SignaturePad>\n  <!-- content -->\n</SignaturePad>\n";
